-- Recommended default RBAC action matrix for the 7 canonical roles.
-- This script is additive: it inserts only missing permissions.

INSERT INTO role_permission (
    role_id,
    module_name,
    action_name,
    permission_code,
    display_name,
    allow_flag,
    created_at,
    created_by
)
SELECT
    r.id,
    seed.module_name,
    seed.action_name,
    seed.permission_code,
    seed.display_name,
    b'1',
    NOW(6),
    'RBAC_DEFAULT_MATRIX'
FROM roles r
JOIN (
    SELECT 'BRANCH_MANAGER' AS role_code, 'BRANCH_MANAGEMENT' AS module_name, 'ASSIGN_USER' AS action_name, 'BRANCH_ASSIGN_USER' AS permission_code, 'Branch Management - Assign Branch User' AS display_name
    UNION ALL SELECT 'BRANCH_MANAGER', 'BRANCH_MANAGEMENT', 'TELLER_LIMIT_MANAGE', 'BRANCH_TELLER_LIMIT_MANAGE', 'Branch Management - Manage Teller Limit'
    UNION ALL SELECT 'BRANCH_MANAGER', 'BRANCH_MANAGEMENT', 'VAULT_MANAGE', 'BRANCH_VAULT_MANAGE', 'Branch Management - Manage Vault'
    UNION ALL SELECT 'BRANCH_MANAGER', 'ATM_CDM', 'CASH_BIN_CREATE', 'ATM_CASH_BIN_CREATE', 'ATM / CDM - Create Cash Bin'
    UNION ALL SELECT 'BRANCH_MANAGER', 'ATM_CDM', 'CASH_BIN_EDIT', 'ATM_CASH_BIN_EDIT', 'ATM / CDM - Edit Cash Bin'
    UNION ALL SELECT 'BRANCH_MANAGER', 'ATM_CDM', 'REPLENISHMENT_CREATE', 'ATM_REPLENISHMENT_CREATE', 'ATM / CDM - Create Replenishment'
    UNION ALL SELECT 'BRANCH_MANAGER', 'ATM_CDM', 'RECONCILIATION_CREATE', 'ATM_RECONCILIATION_CREATE', 'ATM / CDM - Create Reconciliation'
    UNION ALL SELECT 'BRANCH_MANAGER', 'CUSTOMER_MANAGEMENT', 'CREATE', 'CUSTOMER_CREATE', 'Customer Management - Create Customer'
    UNION ALL SELECT 'BRANCH_MANAGER', 'CUSTOMER_MANAGEMENT', 'EDIT', 'CUSTOMER_EDIT', 'Customer Management - Edit Customer'
    UNION ALL SELECT 'BRANCH_MANAGER', 'CUSTOMER_MANAGEMENT', 'ACTIVATE', 'CUSTOMER_ACTIVATE', 'Customer Management - Activate Customer'
    UNION ALL SELECT 'BRANCH_MANAGER', 'CUSTOMER_MANAGEMENT', 'BLOCK', 'CUSTOMER_BLOCK', 'Customer Management - Block Customer'
    UNION ALL SELECT 'BRANCH_MANAGER', 'CUSTOMER_MANAGEMENT', 'ADDRESS_MANAGE', 'CUSTOMER_ADDRESS_MANAGE', 'Customer Management - Manage Customer Address'
    UNION ALL SELECT 'BRANCH_MANAGER', 'CUSTOMER_MANAGEMENT', 'IDENTITY_MANAGE', 'CUSTOMER_IDENTITY_MANAGE', 'Customer Management - Manage Customer Identity'
    UNION ALL SELECT 'BRANCH_MANAGER', 'KYC_MANAGEMENT', 'CREATE', 'KYC_CREATE', 'KYC Management - Create KYC Profile'
    UNION ALL SELECT 'BRANCH_MANAGER', 'KYC_MANAGEMENT', 'EDIT', 'KYC_EDIT', 'KYC Management - Edit KYC Profile'
    UNION ALL SELECT 'BRANCH_MANAGER', 'KYC_MANAGEMENT', 'SUBMIT', 'KYC_SUBMIT', 'KYC Management - Submit KYC Profile'
