    UNION ALL SELECT 'BRANCH_MANAGER', 'CARD_MANAGEMENT', 'EDIT', 'CARD_EDIT', 'Card Management - Edit Card'
    UNION ALL SELECT 'BRANCH_MANAGER', 'CARD_MANAGEMENT', 'ACTIVATE', 'CARD_ACTIVATE', 'Card Management - Activate Card'
