    UNION ALL SELECT 'OPERATIONS_OFFICER', 'CUSTOMER_MANAGEMENT', 'CREATE', 'CUSTOMER_CREATE', 'Customer Management - Create Customer'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'CUSTOMER_MANAGEMENT', 'EDIT', 'CUSTOMER_EDIT', 'Customer Management - Edit Customer'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'CUSTOMER_MANAGEMENT', 'ACTIVATE', 'CUSTOMER_ACTIVATE', 'Customer Management - Activate Customer'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'CUSTOMER_MANAGEMENT', 'BLOCK', 'CUSTOMER_BLOCK', 'Customer Management - Block Customer'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'CUSTOMER_MANAGEMENT', 'ADDRESS_MANAGE', 'CUSTOMER_ADDRESS_MANAGE', 'Customer Management - Manage Customer Address'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'CUSTOMER_MANAGEMENT', 'IDENTITY_MANAGE', 'CUSTOMER_IDENTITY_MANAGE', 'Customer Management - Manage Customer Identity'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'KYC_MANAGEMENT', 'CREATE', 'KYC_CREATE', 'KYC Management - Create KYC Profile'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'KYC_MANAGEMENT', 'EDIT', 'KYC_EDIT', 'KYC Management - Edit KYC Profile'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'KYC_MANAGEMENT', 'SUBMIT', 'KYC_SUBMIT', 'KYC Management - Submit KYC Profile'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'KYC_MANAGEMENT', 'VERIFY', 'KYC_VERIFY', 'KYC Management - Verify KYC Profile'
