    UNION ALL SELECT 'OPERATIONS_OFFICER', 'PROFIT_MANAGEMENT', 'POSTING_RUN', 'PROFIT_POSTING_RUN', 'Profit Management - Run Profit Posting'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'STATEMENTS', 'CUSTOMER_REQUEST', 'STATEMENT_CUSTOMER_REQUEST', 'Statements - Request Customer Statement'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'STATEMENTS', 'BRANCH_REQUEST', 'STATEMENT_BRANCH_REQUEST', 'Statements - Request Branch Statement'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'NOTIFICATION_ALERTS', 'TEMPLATE_CREATE', 'NOTIFICATION_TEMPLATE_CREATE', 'Notification & Alerts - Create Notification Template'
