    UNION ALL SELECT 'OPERATIONS_OFFICER', 'NOTIFICATION_ALERTS', 'EVENT_RULE_CREATE', 'NOTIFICATION_EVENT_RULE_CREATE', 'Notification & Alerts - Create Notification Event Rule'
