    UNION ALL SELECT 'OPERATIONS_OFFICER', 'VERIFICATION', 'SEND_EMAIL_OTP', 'VERIFICATION_SEND_EMAIL_OTP', 'Verification - Send Email Verification OTP'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'VERIFICATION', 'SEND_MOBILE_OTP', 'VERIFICATION_SEND_MOBILE_OTP', 'Verification - Send Mobile Verification OTP'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'VERIFICATION', 'VERIFY_OTP', 'VERIFICATION_VERIFY_OTP', 'Verification - Verify OTP'
    UNION ALL SELECT 'OPERATIONS_OFFICER', 'VERIFICATION', 'RESEND_OTP', 'VERIFICATION_RESEND_OTP', 'Verification - Resend OTP'
