    UNION ALL SELECT 'OPERATIONS_OFFICER', 'ZAKAT_CHARITY', 'BENEFICIARY_RESTORE', 'CHARITY_BENEFICIARY_RESTORE', 'Zakat & Charity - Restore Charity Beneficiary'

