    UNION ALL SELECT 'CUSTOMER', 'STATEMENTS', 'CUSTOMER_REQUEST', 'STATEMENT_CUSTOMER_REQUEST', 'Statements - Request Customer Statement'
    UNION ALL SELECT 'CUSTOMER', 'DEPOSIT_SCHEMES', 'ENROLLMENT_CREATE', 'DEPOSIT_SCHEME_ENROLLMENT_CREATE', 'Deposit Schemes - Create Deposit Scheme Enrollment'
