) seed
    ON seed.role_code = r.code
LEFT JOIN role_permission rp
    ON rp.role_id = r.id
   AND UPPER(rp.permission_code) = seed.permission_code
WHERE rp.id IS NULL;

SELECT r.code, COUNT(rp.id) AS permission_count
FROM roles r
LEFT JOIN role_permission rp ON rp.role_id = r.id
GROUP BY r.code
ORDER BY r.code;
